import{_ as t,o as e,c as q,a2 as u}from"./chunks/framework.Crpw6aS5.js";const s=JSON.parse('{"title":"金句 · 按场景","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-scene/index.md","filePath":"05_quotes/by-scene/index.md"}'),a={name:"05_quotes/by-scene/index.md"};function l(c,o,b,p,r,k){return e(),q("div",null,[...o[0]||(o[0]=[u('<h1 id="金句-·-按场景" tabindex="-1">金句 · 按场景 <a class="header-anchor" href="#金句-·-按场景" aria-label="Permalink to &quot;金句 · 按场景&quot;">​</a></h1><blockquote><p>投资是一场关于判断力、耐心和品格的长期修行。场景化语录，助你应对真实决策时刻。</p></blockquote><hr><h2 id="💰-投资决策" tabindex="-1">💰 投资决策 <a class="header-anchor" href="#💰-投资决策" aria-label="Permalink to &quot;💰 投资决策&quot;">​</a></h2><blockquote><p>&quot;投资的全部意义在于，在好公司以合理价格买入。但合理价格远低于内在价值时买入，就是安全边际。&quot;</p></blockquote><blockquote><p>&quot;要进行成功的投资，您不需要理解贝塔系数，有效市场理论、现代投资组合理论、期权定价或新兴市场。事实上，您对这些一无所知反而更好。&quot;</p></blockquote><blockquote><p>&quot;我们选择可交易股权的方法，和我们评估整体收购企业时一模一样：业务好理解，有长期前景，由诚实能干的人运营，价格有吸引力。&quot;</p></blockquote><blockquote><p>&quot;你不需要知道一个人的精确年龄才能知道他有投票权，也不需要知道他的确切体重才能认出他需要节食。投资也是如此：模糊的正确好过精确的错误。&quot;</p></blockquote><blockquote><p>&quot;如果它们的业务表现持续让我们满意，我们甚至欢迎我们持有的股票市场价格下跌，这样我们就能以更好的价格买到更多。&quot;</p></blockquote><p>→ <a href="/search.html?q=投资决策">05_quotes/by-scene/投资决策</a></p><hr><h2 id="🤝-企业收购" tabindex="-1">🤝 企业收购 <a class="header-anchor" href="#🤝-企业收购" aria-label="Permalink to &quot;🤝 企业收购&quot;">​</a></h2><blockquote><p>&quot;收购就像婚姻：婚前要充分了解对方，婚后要充分容忍对方。&quot;</p></blockquote><blockquote><p>&quot;找到一个好的收购对象需要一个买家的运气。找到一个好的买家需要一个卖家的运气。两者兼备需要几十年的积累。&quot;</p></blockquote><blockquote><p>&quot;我们通过收购建立商业帝国，但真正重要的是找到那些有护城河、有优秀管理者的企业。&quot;</p></blockquote><blockquote><p>&quot;好的收购是锦上添花，坏的收购是灾难一场。买贵了，再好的企业也会变成糟糕的投资。&quot;</p></blockquote><blockquote><p>&quot;我们对子公司经理的期望很简单：把企业当成你们自己100%拥有一样去经营。&quot;</p></blockquote><p>→ <a href="/search.html?q=企业收购">05_quotes/by-scene/企业收购</a></p><hr><h2 id="👤-人才管理" tabindex="-1">👤 人才管理 <a class="header-anchor" href="#👤-人才管理" aria-label="Permalink to &quot;👤 人才管理&quot;">​</a></h2><blockquote><p>&quot;找一个比你更聪明、更有品格的人，然后充分授权。不要干涉他们如何经营业务。&quot;</p></blockquote><blockquote><p>&quot;找一个对的人，给他们资源，然后让他们自由发挥。这就是我们在伯克希尔管理子公司的方式。&quot;</p></blockquote><blockquote><p>&quot;我们伯克希尔的经理们，他们拥有的正是他们想要的工作，因此他们专心致志于最大化他们拥有并热爱的企业的长期价值。&quot;</p></blockquote><blockquote><p>&quot;真正的人才不需要管理，他们需要的是使命感和自主权。&quot;</p></blockquote><p>→ <a href="/search.html?q=人才管理">05_quotes/by-scene/人才管理</a></p><hr><h2 id="📈-市场时机" tabindex="-1">📈 市场时机 <a class="header-anchor" href="#📈-市场时机" aria-label="Permalink to &quot;📈 市场时机&quot;">​</a></h2><blockquote><p>&quot;长期来看，市场价格会回归内在价值。短期内市场是投票机，长期是称重机。&quot;</p></blockquote><blockquote><p>&quot;市场短期是投票机，长期是称重机。在短期内，市场是一个情绪化的投票机器，而不是理性的称重机器。&quot;</p></blockquote><blockquote><p>&quot;预测市场短期走势是不可能的。那些声称能做到的人，要么是在欺骗自己，要么是在欺骗别人。&quot;</p></blockquote><blockquote><p>&quot;在别人恐惧时贪婪，在别人贪婪时恐惧。这句话所有人都知道，但做到需要勇气。&quot;</p></blockquote><p>→ <a href="/search.html?q=市场时机">05_quotes/by-scene/市场时机</a></p><hr><h2 id="⚡-危机应对" tabindex="-1">⚡ 危机应对 <a class="header-anchor" href="#⚡-危机应对" aria-label="Permalink to &quot;⚡ 危机应对&quot;">​</a></h2><blockquote><p>&quot;恐惧会传染。金融系统崩溃往往不是因为基本面有多差，而是因为恐惧本身。&quot;</p></blockquote><blockquote><p>&quot;当流动性充足时，人们往往意识不到它的存在；当流动性消失时，每个人都在寻找它。&quot;</p></blockquote><blockquote><p>&quot;当别人都在冒险的时候，安全边际是你最好的朋友。&quot;</p></blockquote><blockquote><p>&quot;我在2008年金融危机最恐慌的时候买入了一些最好的资产。当时所有人都在恐惧，我试图保持贪婪。&quot;</p></blockquote><blockquote><p>&quot;我们从未对美国的长期未来失去信心。在恐慌时刻，我们选择加码，而不是退出。&quot;</p></blockquote><p>→ <a href="/search.html?q=危机应对">05_quotes/by-scene/危机应对</a></p><hr><h2 id="🌟-人生选择" tabindex="-1">🌟 人生选择 <a class="header-anchor" href="#🌟-人生选择" aria-label="Permalink to &quot;🌟 人生选择&quot;">​</a></h2><blockquote><p>&quot;做你热爱的事，成功会随之而来。如果你热爱你所做的，你会找到一种方法把事情做好。&quot;</p></blockquote><blockquote><p>&quot;人生中最重要的决定是你选择和谁一起工作、和谁结婚。这些选择的权重远超任何职业决定。&quot;</p></blockquote><blockquote><p>&quot;我之所以富有，不是因为我赚得多，而是因为我让利润长期复利增长。从1965年开始，伯克希尔从未停止过复利的脚步。&quot;</p></blockquote><blockquote><p>&quot;找到你真正理解的业务，长期持有。不要为了多元化而分散注意力，真正的多元化是对知识的多元化。&quot;</p></blockquote><blockquote><p>&quot;每天早上醒来，你应该在镜子前问自己：&#39;如果这家公司是我唯一拥有的资产，我会怎么想？&#39; 如果答案让你不舒服，那就是卖出的信号。&quot;</p></blockquote><p>→ <a href="/search.html?q=人生选择">05_quotes/by-scene/人生选择</a></p>',48)])])}const n=t(a,[["render",l]]);export{s as __pageData,n as default};
